  ('judicial-f0899a01-moex-00232', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依實務見解，關於中止犯之規定，下列敘述何者正確？', '["只要中止或防止其結果之發生者即屬之", "法律效果為不罰", "預備犯不適用之", "行為人只要因己意中止犯行，即成立中止犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
